private rule IsPE : PE
{
	meta:
		description = "Identifier for PE files"
		last_modified = "2014-07-11"

	strings:
		$magic = { 5a 4d }

	condition:
		$magic at 0 and uint32( uint32( 0x3C ) ) == 0x00004550
}

